module RefModule (
    input wire clk,
    input wire reset,
    output reg osc_out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            osc_out <= 0;
        end else begin
            osc_out <= ~osc_out;
        end
    end
endmodule
